    bmi  _L_z00_DriveTune1_PrepNote
    bne  _L_z00_DriveTune1_PlayNote
    ; We've reached the end of the tune.
    ;
    ; If tune is "Game Over", then go play it again.
    ;
    move.b  ($0607,A4),D0
    cmpi.b  #$40,D0
    beq  _L_z00_DriveTune1_ChangeTune
    move.b  #$90,D2
    move.l  D0,-(SP)       ; save A (6502 STX/STY never modifies A)
    move.b  D2,D0  ; D2 → D0 for I/O write
    bsr     _apu_write_4004  ; APU/IO write
    move.l  (SP)+,D0       ; restore A
    moveq   #24,D2
    move.l  D0,-(SP)       ; save A (6502 STX/STY never modifies A)
    move.b  D2,D0  ; D2 → D0 for I/O write
    bsr     _apu_write_4007  ; APU/IO write
    move.l  (SP)+,D0       ; restore A
    moveq   #0,D2
    move.b  D2,($0607,A4)
    move.l  D0,-(SP)       ; save A (6502 STX/STY never modifies A)
    move.b  D2,D0  ; D2 → D0 for I/O write
    bsr     _apu_write_4006  ; APU/IO write
    move.l  (SP)+,D0       ; restore A
    rts

    even
_L_z00_DriveTune1_PrepNote:
    andi.b #$7F,D0
    move.b  D0,($006E,A4)
    move.b  ($0618,A4),D3
    addq.b  #1,($0618,A4)
    lea     (TuneScripts1).l,A0
    move.b  (A0,D3.W),D0
    even
_L_z00_DriveTune1_PlayNote:
    bsr     EmitSquareNote1
    moveq   #127,D0
    bsr     _apu_write_4005  ; APU/IO write
    move.b  #$86,D0
    bsr     _apu_write_4004  ; APU/IO write
    move.b  ($006E,A4),D0
    move.b  D0,($006F,A4)
    moveq   #31,D0
    move.b  D0,($006D,A4)
    even
_L_z00_DriveTune1_CheckVibrate:
    ; If the tune is not one of "flute" or "Link dying", then return.
    ;
    move.b  ($0607,A4),D0
    andi.b #$90,D0
    beq  _L_z00_DriveTune1_Exit
    move.b  ($006D,A4),D3
    beq  _anon_z00_6
    subq.b  #1,($006D,A4)
_anon_z00_6:
    lea     (CustomEnvelopeTune1).l,A0
    move.b  (A0,D3.W),D0
    bsr     _apu_write_4004  ; APU/IO write
    move.b  ($006F,A4),D0
    move.b  ($006B,A4),D2
    bsr     VibratePitch
    move.l  D0,-(SP)       ; save A (6502 STX/STY never modifies A)
    move.b  D2,D0  ; D2 → D0 for I/O write
    bsr     _apu_write_4006  ; APU/IO write
    move.l  (SP)+,D0       ; restore A
    even
_L_z00_DriveTune1_Exit:
    rts

    even
CustomEnvelopeTune1:
    dc.b    $95, $96, $97, $98, $99, $9A, $9B, $9C
    dc.b    $9D, $9E, $9F, $9F, $9F, $9F, $9F, $9F
    dc.b    $9F, $9F, $9F, $9F, $9F, $9F, $9F, $9E
    dc.b    $9D, $9C, $9B, $9A, $99, $98, $97, $96

    even
DriveSample:
    move.b  ($0601,A4),D0
    bmi  _L_z00_DriveSample_ChangeSampleMid
    bne  _L_z00_DriveSample_ChangeSampleLow
    move.b  ($0608,A4),D0
    beq  _L_z00_DriveSample_CheckBgSample
    subq.b  #1,($05F2,A4)
    bne  _L_z00_DriveSample_Exit
    move.b  ($0608,A4),D0
    bmi  _L_z00_DriveSample_ChangeSampleMid
    andi.b #$70,D0
    bne  _L_z00_DriveSample_ChangeSampleLow
    moveq   #0,D0
    move.b  D0,($0608,A4)
    moveq   #15,D0
    bsr     _apu_write_4015  ; APU/IO write
    even
_L_z00_DriveSample_CheckBgSample:
    move.b  ($05F6,A4),D0
    bne  _anon_z00_7
    even
_L_z00_DriveSample_Exit:
    rts

    even
_L_z00_DriveSample_ChangeSampleLow:
    moveq   #0,D2
    beq  _anon_z00_7
    even
_L_z00_DriveSample_ChangeSampleMid:
    moveq   #127,D2
    andi.b #$F0,D0
_anon_z00_7:
    move.l  D0,-(SP)       ; save A (6502 STX/STY never modifies A)
    move.b  D2,D0  ; D2 → D0 for I/O write
    bsr     _apu_write_4011  ; APU/IO write
    move.l  (SP)+,D0       ; restore A
    move.b  D0,($0608,A4)
    move.b  D0,D2
    andi.b #$F0,D0
    beq  _anon_z00_8
    move.b  D0,($05F6,A4)
_anon_z00_8:
    move.b  D2,D0
    moveq   #0,D3
_anon_z00_9:
    addq.b  #1,D3
    lsr.b  #1,D0   ; LSR A
    bcc  _anon_z00_9
    lea     (SampleRates-1).l,A0
    move.b  (A0,D3.W),D0
    bsr     _apu_write_4010  ; APU/IO write
    lea     (SampleAddrs-1).l,A0
    move.b  (A0,D3.W),D0
    bsr     _apu_write_4012  ; APU/IO write
    lea     (SampleLengths-1).l,A0
    move.b  (A0,D3.W),D0
    bsr     _apu_write_4013  ; APU/IO write
    move.b  #$A0,D0
    move.b  D0,($05F2,A4)
    moveq   #15,D0
    bsr     _apu_write_4015  ; APU/IO write
    moveq   #31,D0
    bsr     _apu_write_4015  ; APU/IO write
    rts

    even
SampleAddrs:
    dc.b    $00, $4C, $80, $1D, $20, $28, $4C

    even
SampleLengths:
    dc.b    $75, $C0, $40, $0A, $B0, $90, $D0

    even
SampleRates:
    dc.b    $0F, $0F, $0D, $0F, $0E, $0F, $0E

; Params:
; X: duty byte
; Y: sweep byte
;
    even
SetSq0DutyAndSweep:
    move.l  D0,-(SP)       ; save A (6502 STX/STY never modifies A)
    move.b  D3,D0  ; D3 → D0 for I/O write
    bsr     _apu_write_4001  ; APU/IO write
    move.l  (SP)+,D0       ; restore A
    move.l  D0,-(SP)       ; save A (6502 STX/STY never modifies A)
    move.b  D2,D0  ; D2 → D0 for I/O write
    bsr     _apu_write_4000  ; APU/IO write
    move.l  (SP)+,D0       ; restore A
    rts

    even
EmitSquareNoteWithDutyAndSweep0:
    bsr     SetSq0DutyAndSweep
; Params:
; A: offset of a note in period table
;
    even
EmitSquareNote0:
    move.b  D0,D3
    lea     (NotePeriodTable+1).l,A0
    move.b  (A0,D3.W),D0
    beq  Exit
    move.b  D0,($006A,A4)
    bsr     _apu_write_4002  ; APU/IO write
    lea     (NotePeriodTable).l,A0
    move.b  (A0,D3.W),D0
    ori.b #$08,D0
    bsr     _apu_write_4003  ; APU/IO write
    even
    IFND Exit
Exit:
    ENDC
    rts

; Params:
; X: duty byte
; Y: sweep byte
;
    even
SetSq1DutyAndSweep:
    move.l  D0,-(SP)       ; save A (6502 STX/STY never modifies A)
    move.b  D2,D0  ; D2 → D0 for I/O write
    bsr     _apu_write_4004  ; APU/IO write
    move.l  (SP)+,D0       ; restore A
    move.l  D0,-(SP)       ; save A (6502 STX/STY never modifies A)
    move.b  D3,D0  ; D3 → D0 for I/O write
    bsr     _apu_write_4005  ; APU/IO write
    move.l  (SP)+,D0       ; restore A
    rts

    even
EmitSquareNoteWithDutyAndSweep1:
    bsr     SetSq1DutyAndSweep
; Params:
; A: note ID (offset of note in period table)
;
; Returns:
; Y: note ID
; A: 0 if the note is a a rest
;
    even
EmitSquareNote1:
    move.b  D0,D3
    lea     (NotePeriodTable+1).l,A0
    move.b  (A0,D3.W),D0
    beq  Exit
    move.b  D0,($006B,A4)
    bsr     _apu_write_4006  ; APU/IO write
    lea     (NotePeriodTable).l,A0
    move.b  (A0,D3.W),D0
    ori.b #$08,D0
    bsr     _apu_write_4007  ; APU/IO write
    rts

; Params:
; A: offset of a note in period table
;
    even
EmitTriangleNote:
    move.b  D0,D3
    lea     (NotePeriodTable+1).l,A0
    move.b  (A0,D3.W),D0
    beq  Exit
    move.b  D0,($05F0,A4)
    bsr     _apu_write_400a  ; APU/IO write
    lea     (NotePeriodTable).l,A0
    move.b  (A0,D3.W),D0
    ori.b #$08,D0
    bsr     _apu_write_400b  ; APU/IO write
    rts

; Params:
; A: note counter
; X: period value
;
; Returns:
; X: (period - 1) to (period + 1)
;
; If note counter < $10, then return.
;
    even
VibratePitch:
    cmpi.b  #$10,D0
    bcs  _L_z00_VibratePitch_Exit
    ; Is bit 2 set?
    ;
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    bcs  _L_z00_VibratePitch_GoDown
    ; If not set, then add 1 to X.
    ;
    move.b  D2,D0
    move.b  #$01,D1
    addx.b  D1,D0   ; ADC #$01 (X flag = 6502 C)
    bne  _anon_z00_10
    even
_L_z00_VibratePitch_GoDown:
    ; If set, then subtract 1 from X.
    ;
    move.b  D2,D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$FF,D1
    addx.b  D1,D0   ; ADC #$FF (X flag = 6502 C)
_anon_z00_10:
    move.b  D0,D2
    even
_L_z00_VibratePitch_Exit:
    rts

    even
KeepPlaying:
    jmp     KeepPlayingSong

    even
DriveSong:
    move.b  ($0600,A4),D0
    bne  _L_z00_DriveSong_ChangeSong
    move.b  ($0609,A4),D0
    bne  KeepPlaying
    rts

    even
_L_z00_DriveSong_ChangeSong:
    move.b  D0,($0609,A4)
    bmi  _L_z00_DriveSong_PlayFirstDemoPhrase
    cmpi.b  #$06,D0
    bne  _anon_z00_11
    moveq   #36,D3
    bne  PrepPhrase
_anon_z00_11:
    cmpi.b  #$01,D0
    beq  _L_z00_DriveSong_PlayFirstOverworldPhrase
    cmpi.b  #$40,D0
    beq  _L_z00_DriveSong_PlayFirstUnderworldPhrase
    cmpi.b  #$10,D0
    bne  PlayNextPhrase
    moveq   #17,D3
    bne  SetPrevPhraseIndex
    even
_L_z00_DriveSong_PlayFirstDemoPhrase:
    moveq   #25,D3
    bne  SetPrevPhraseIndex
    even
_L_z00_DriveSong_PlayFirstUnderworldPhrase:
    moveq   #15,D3
    bne  SetPrevPhraseIndex
    even
_L_z00_DriveSong_PlayFirstOverworldPhrase:
    moveq   #8,D3
    even
SetPrevPhraseIndex:
    move.b  D3,($006C,A4)
    even
PlayNextPhrase:
    move.b  D0,D2
    bmi  _L_z00_PlayNextPhrase_PlayNextDemoPhrase
    cmpi.b  #$01,D0
    beq  _L_z00_PlayNextPhrase_PlayNextOverworldPhrase
    cmpi.b  #$40,D0
    beq  _L_z00_PlayNextPhrase_PlayNextUnderworldPhrase
    cmpi.b  #$10,D0
    bne  _L_z00_PlayNextPhrase_PlaySinglePhraseSong
    ; Play the next phrase of the ending song.
    ;
    addq.b  #1,($006C,A4)
    move.b  ($006C,A4),D3
    cmpi.b  #$1A,D3
    bne  PrepPhrase
    moveq   #20,D3
    bne  SetPrevPhraseIndex
    even
_L_z00_PlayNextPhrase_PlayNextUnderworldPhrase:
    addq.b  #1,($006C,A4)
    move.b  ($006C,A4),D3
    cmpi.b  #$12,D3
    bne  PrepPhrase
    moveq   #15,D3
    bne  SetPrevPhraseIndex
    even
_L_z00_PlayNextPhrase_PlayNextOverworldPhrase:
    addq.b  #1,($006C,A4)
    move.b  ($006C,A4),D3
    cmpi.b  #$10,D3
    bne  PrepPhrase
    moveq   #9,D3
    bne  SetPrevPhraseIndex
    even
_L_z00_PlayNextPhrase_PlayNextDemoPhrase:
    addq.b  #1,($006C,A4)
    move.b  ($006C,A4),D3
    cmpi.b  #$24,D3
    bne  PrepPhrase
    moveq   #25,D3
    bne  SetPrevPhraseIndex
    even
_L_z00_PlayNextPhrase_PlaySinglePhraseSong:
    ; Get the index for the song bit: 2 to 6.
    ;
    move.b  D2,D0
    moveq   #0,D3
_anon_z00_12:
    addq.b  #1,D3
    lsr.b  #1,D0   ; LSR A
    bcc  _anon_z00_12
    even
PrepPhrase:
    lea     (SongTable-1).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,D3
    lea     (SongTable).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($05F4,A4)
    lea     (SongTable+1).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($0066,A4)
    lea     (SongTable+2).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($0067,A4)
    lea     (SongTable+3).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($060C,A4)
    lea     (SongTable+4).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($060B,A4)
    lea     (SongTable+5).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($060D,A4)
    move.b  D0,($05F5,A4)
    lea     (SongTable+6).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($0619,A4)
    lea     (SongTable+7).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($05F1,A4)
    moveq   #1,D0
    move.b  D0,($0611,A4)
    move.b  D0,($0613,A4)
    move.b  D0,($0616,A4)
    move.b  D0,($0617,A4)
    lsr.b  #1,D0   ; LSR A
    move.b  D0,($060A,A4)
    even
KeepPlayingSong:
    subq.b  #1,($0611,A4)
    bne  ApplySq1Effects
    move.b  ($060A,A4),D3
    addq.b  #1,($060A,A4)
    move.b  ($66,A4),D1   ; ptr lo
    move.b  ($67,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4             ; D4 = NES ptr addr
    ext.l   D4
    add.l   #NES_RAM,D4       ; → Genesis addr
    movea.l D4,A0
    move.b  (A0,D3.W),D0     ; LDA ($nn),Y
    beq  _L_z00_KeepPlayingSong_SongEnded
    bpl  PlayNote
    bne  PrepNote
    even
_L_z00_KeepPlayingSong_SongEnded:
    ; If this is a song that repeats, then go play again.
    ;
    move.b  ($0609,A4),D0
    andi.b #$F1,D0
    bne  PlayAgain
    even
SilenceSong:
    moveq   #0,D0
    move.b  D0,($0609,A4)
    bsr     _apu_write_4015  ; APU/IO write
    moveq   #15,D0
    bsr     _apu_write_4015  ; APU/IO write
    rts

    even
PlayAgain:
    jmp     PlayNextPhrase

    even
PrepNote:
    bsr     GetSongNoteLength
    move.b  D0,($0610,A4)
    move.b  ($060A,A4),D3
    addq.b  #1,($060A,A4)
    move.b  ($66,A4),D1   ; ptr lo
    move.b  ($67,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4             ; D4 = NES ptr addr
    ext.l   D4
    add.l   #NES_RAM,D4       ; → Genesis addr
    movea.l D4,A0
    move.b  (A0,D3.W),D0     ; LDA ($nn),Y
    even
PlayNote:
    ; If something is playing in tune channel 1, then
    ; don't play a square note here.
    ;
    move.b  ($0607,A4),D2
    bne  _L_z00_PlayNote_SkipSq1
    bsr     EmitSquareNote1
    beq  _anon_z00_13
    bsr     PrepareCustomSongEnvelope
_anon_z00_13:
    move.b  D0,($0612,A4)
    bsr     SetSq1DutyAndSweep
    moveq   #0,D0
    move.b  D0,($061B,A4)
    even
_L_z00_PlayNote_SkipSq1:
    move.b  ($0610,A4),D0
    move.b  D0,($0611,A4)
    even
ApplySq1Effects:
    ; If something is playing in tune channel 1, then
    ; skip effects for square channel 1.
    ;
    move.b  ($0607,A4),D3
    bne  _L_z00_ApplySq1Effects_HandleSq0
    addq.b  #1,($061B,A4)
    move.b  ($0612,A4),D3
    beq  _anon_z00_14
    subq.b  #1,($0612,A4)
_anon_z00_14:
    bsr     ShapeSongVolume
    bsr     _apu_write_4004  ; APU/IO write
    moveq   #127,D2
    move.l  D0,-(SP)       ; save A (6502 STX/STY never modifies A)
    move.b  D2,D0  ; D2 → D0 for I/O write
    bsr     _apu_write_4005  ; APU/IO write
    move.l  (SP)+,D0       ; restore A
    move.b  ($0609,A4),D0
    bpl  _L_z00_ApplySq1Effects_HandleSq0
    ; The demo/title song ($80) vibrates the pitch.
    ;
    move.b  ($061B,A4),D0
    move.b  ($006B,A4),D2
    bsr     VibratePitch
    move.l  D0,-(SP)       ; save A (6502 STX/STY never modifies A)
    move.b  D2,D0  ; D2 → D0 for I/O write
    bsr     _apu_write_4006  ; APU/IO write
    move.l  (SP)+,D0       ; restore A
    even
_L_z00_ApplySq1Effects_HandleSq0:
    move.b  ($060B,A4),D3
    beq  _L_z00_ApplySq1Effects_HandleTrg
    subq.b  #1,($0613,A4)
    bne  _L_z00_ApplySq1Effects_ApplySq0Effects
    move.b  ($060B,A4),D3
    addq.b  #1,($060B,A4)
    move.b  ($66,A4),D1   ; ptr lo
    move.b  ($67,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4             ; D4 = NES ptr addr
    ext.l   D4
    add.l   #NES_RAM,D4       ; → Genesis addr
    movea.l D4,A0
    move.b  (A0,D3.W),D0     ; LDA ($nn),Y
    bpl  _L_z00_ApplySq1Effects_PlaySq0
    bsr     GetSongNoteLength
    move.b  D0,($060F,A4)
    move.b  ($060B,A4),D3
    addq.b  #1,($060B,A4)
    move.b  ($66,A4),D1   ; ptr lo
    move.b  ($67,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4             ; D4 = NES ptr addr
    ext.l   D4
    add.l   #NES_RAM,D4       ; → Genesis addr
    movea.l D4,A0
    move.b  (A0,D3.W),D0     ; LDA ($nn),Y
    even
_L_z00_ApplySq1Effects_PlaySq0:
    move.b  ($0605,A4),D2
    bne  _L_z00_ApplySq1Effects_SkipSq0
    bsr     EmitSquareNote0
    beq  _anon_z00_15
    bsr     PrepareCustomSongEnvelope
_anon_z00_15:
    move.b  D0,($0614,A4)
    bsr     SetSq0DutyAndSweep
    moveq   #0,D0
    move.b  D0,($061C,A4)
    even
_L_z00_ApplySq1Effects_SkipSq0:
    move.b  ($060F,A4),D0
    move.b  D0,($0613,A4)
    even
_L_z00_ApplySq1Effects_ApplySq0Effects:
    move.b  ($0605,A4),D2
    bne  _L_z00_ApplySq1Effects_HandleTrg
    addq.b  #1,($061C,A4)
    move.b  ($0614,A4),D3
    beq  _anon_z00_16
    subq.b  #1,($0614,A4)
_anon_z00_16:
    bsr     ShapeSongVolume
    bsr     _apu_write_4000  ; APU/IO write
    move.b  ($0609,A4),D0
    bpl  _anon_z00_17
    ; The demo/title song ($80) vibrates the pitch.
    ;
    move.b  ($061C,A4),D0
    move.b  ($006A,A4),D2
    bsr     VibratePitch
    move.l  D0,-(SP)       ; save A (6502 STX/STY never modifies A)
